SELECT server_id, AVG(usr + sys) AS avg_cpu_usage
FROM server_performance
GROUP BY server_id;

SELECT server_id, timestamp_ms
FROM server_performance
WHERE metric_status = 'active';

SELECT DISTINCT user_id
FROM access_logs
WHERE access_date >= DATE('now', '-1 month');

SELECT server_type_name, max_cpu_usage
FROM server_types
WHERE max_cpu_usage > 50.0;
